// Disparado por Schedule Trigger: guarda el payload final en staticData del workflow.
// El webhook leerá esta caché y responderá al instante (<200ms) → adiós 504.
const payload = $input.first().json;
const staticData = $getWorkflowStaticData('global');
staticData.cached_payload = payload;
staticData.cached_at      = new Date().toISOString();
return [{ json: { saved: true, cached_at: staticData.cached_at, _ticket_keys: Object.keys(payload || {}).length } }];

// Disparado por el webhook: lee el último payload cacheado y lo emite tal cual.
// Si la caché está vacía (primer arranque o reset), devuelve estructura mínima con _stale=true.
const staticData = $getWorkflowStaticData('global');
const cached = staticData.cached_payload || null;
if (!cached) {
  return [{ json: {
    generated_at: null,
    cached_at: null,
    _stale: true,
    _hint: 'Cache vacía. Espera al primer tick del Schedule Trigger (5 min) o ejecútalo manualmente.',
    hourly_today: [],
    weekly_stacked: [],
    top_orgs: []
  } }];
}
return [{ json: { ...cached, cached_at: staticData.cached_at, _stale: false } }];
